import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Secure code - handling the length of userInput properly
        byte[] buffer = new byte[Math.min(userInput.length(), 10)];
        Arrays.fill(buffer, (byte) 0); // Fill buffer with zeros

        System.arraycopy(userInput.getBytes(), 0, buffer, 0, Math.min(userInput.length(), buffer.length));

        System.out.println("Input processed successfully.");
    }
}

### Explanation:
취약유형: Buffer Overflow
